      <div
        style={{
          display: "flex",
          alignItems: "center",
          gap: 56,
          transform: `scale(${scale})`,
          opacity: Math.min(wrapOpacity, dissolveOp),
          filter: `blur(${blurPx}px)`,
        }}
      >
        {/* ── Donut chart ─────────────────────────────────────────────── */}
        <div
          style={{
            position: "relative",
            width: DONUT,
            height: DONUT,
            flexShrink: 0,
          }}
        >
