            width={DONUT}
            height={DONUT}
            viewBox="0 0 200 200"
            style={{ overflow: "visible" }}
          >
            {/* Background track */}
            <circle
              cx="100" cy="100" r="78"
              fill="none"
              stroke="rgba(0,0,0,0.08)"
              strokeWidth="34"
            />

