            <circle
              cx="100" cy="100" r="78"
              fill="none"
              stroke="#415a77"
              strokeWidth="34"
              strokeLinecap="butt"
              strokeDasharray={`${GAP_LEN} ${C}`}
              strokeDashoffset={gapOffset}
              transform={`rotate(${GAP_DEG} 100 100)`}
              style={{
                filter: `drop-shadow(0 0 ${glow}px rgba(65,90,119,0.7))`,
              }}
            />

            {/* Quick Task — 5/28 of ring, gray */}
            <circle
              cx="100" cy="100" r="78"
              fill="none"
              stroke="#c2a46d"
              strokeWidth="34"
              strokeLinecap="butt"
              strokeDasharray={`${TASK_LEN} ${C}`}
              strokeDashoffset={taskOffset}
              transform={`rotate(${TASK_DEG} 100 100)`}
            />
          </svg>

          {/* Center label overlay */}
          <div
            style={{
              position: "absolute",
              inset: 0,
              display: "flex",
              flexDirection: "column",
              alignItems: "center",
              justifyContent: "center",
              opacity: centerOp,
              transform: `scale(${centerScale})`,
            }}
          >
            <span
              style={{
                fontSize: 62,
                fontWeight: 800,
                color: "#1D1D1F",
                letterSpacing: "-0.05em",
                lineHeight: 1,
                textShadow: "none",
              }}
            >
              {centerNum}
            </span>
            <span
              style={{
                fontSize: 11,
                fontWeight: 800,
                color: "rgba(29,29,31,0.45)",
                letterSpacing: "0.2em",
                textTransform: "uppercase",
                marginTop: 4,
              }}
            >
              MIN LOST
            </span>
          </div>
        </div>

        {/* ── Labels ──────────────────────────────────────────────────── */}
        <div style={{ display: "flex", flexDirection: "column", gap: 32 }}>

          {/* Quick Task */}
          <div
            style={{
              opacity: lbl1Op,
              transform: `translateX(${lbl1X}px)`,
            }}
          >
            <div style={{ display: "flex", alignItems: "center", gap: 13 }}>
              <div
                style={{
                  width: 13, height: 13,
                  borderRadius: "50%",
                  background: "#c2a46d",
                  flexShrink: 0,
                }}
              />
              <span
                style={{
                  fontSize: 48,
                  fontWeight: 800,
                  color: "#1D1D1F",
                  letterSpacing: "-0.04em",
                  lineHeight: 1,
                  textShadow: "none",
                }}
              >
                5
              </span>
              <span
                style={{
                  fontSize: 12,
                  fontWeight: 800,
                  color: "rgba(29,29,31,0.45)",
                  letterSpacing: "0.08em",
                  alignSelf: "flex-end",
                  paddingBottom: 6,
                }}
              >
                MIN
              </span>
            </div>
            <div
              style={{
                fontSize: 12,
                fontWeight: 800,
                color: "rgba(29,29,31,0.6)",
                letterSpacing: "0.1em",
