import React from "react";
import { Composition } from "remotion";

// ── Script 1: Focus / Productivity ────────────────────────────────────────
import { FocusPie }       from "./FocusPie";
import { FourHoursCost }  from "./FourHoursCost";
import { TwentyThreeMin } from "./TwentyThreeMin";
import { SwitchingCost }  from "./SwitchingCost";
import { NinetyDays }     from "./NinetyDays";

// ── Script 2: DIY Video / Physics of Looking Pro ──────────────────────────
import { FiveKvsPhysics }        from "./FiveKvsPhysics";
import { InterrogationShadows }  from "./InterrogationShadows";
import { ThreeFixes }            from "./ThreeFixes";
import { HundredBeats }          from "./HundredBeats";

export const Root: React.FC = () => {
  return (
    <>
      {/* ── Script 1: Focus / Productivity ─────────────────────────────── */}

      {/* [0:00-0:15] Focus Recovery Gap pie chart */}
      <Composition id="FocusPie"       component={FocusPie}       durationInFrames={90}  fps={30} width={1920} height={1080} />

      {/* [0:15-0:25] 4 HRS for 60 SEC */}
      <Composition id="FourHoursCost"  component={FourHoursCost}  durationInFrames={90}  fps={30} width={1920} height={1080} />

      {/* [0:40-0:50] 23 Minutes anchor card */}
      <Composition id="TwentyThreeMin" component={TwentyThreeMin} durationInFrames={90}  fps={30} width={1920} height={1080} />

      {/* [1:10-1:35] Switching cost — 6 seconds */}
      <Composition id="SwitchingCost"  component={SwitchingCost}  durationInFrames={180} fps={30} width={1920} height={1080} />

      {/* [1:42-1:55] 90 Days → 1 Afternoon */}
      <Composition id="NinetyDays"     component={NinetyDays}     durationInFrames={90}  fps={30} width={1920} height={1080} />

      {/* ── Script 2: DIY Video / Physics of Looking Pro ────────────────── */}

      {/* [0:30-0:38] £5,000 camera vs basic physics */}
      <Composition id="FiveKvsPhysics"       component={FiveKvsPhysics}       durationInFrames={90}  fps={30} width={1920} height={1080} />

      {/* [1:12-1:20] Interrogation Shadows coined term */}
      <Composition id="InterrogationShadows" component={InterrogationShadows} durationInFrames={90}  fps={30} width={1920} height={1080} />

      {/* [1:10-1:45] 3 Fixes — no gear required — 6 seconds */}
      <Composition id="ThreeFixes"           component={ThreeFixes}           durationInFrames={180} fps={30} width={1920} height={1080} />

      {/* [1:47-1:55] £100 setup beats £5,000 camera */}
      <Composition id="HundredBeats"         component={HundredBeats}         durationInFrames={90}  fps={30} width={1920} height={1080} />
    </>
  );
};

